import{_ as t,o as r,c as o,a2 as a}from"./chunks/framework.CVB7JJFU.js";const p=JSON.parse('{"title":"Correctness Model","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/correctness-model.md","filePath":"concepts/correctness-model.md","lastUpdated":1781637126000}'),n={name:"concepts/correctness-model.md"};function s(i,e,c,d,l,u){return r(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="correctness-model" tabindex="-1">Correctness Model <a class="header-anchor" href="#correctness-model" aria-label="Permalink to &quot;Correctness Model&quot;">​</a></h1><p>AOSC&#39;s correctness model is based on backfill, source operation-history replay, and a write-blocked cutover.</p><h2 id="what-aosc-tries-to-preserve" tabindex="-1">What AOSC Tries to Preserve <a class="header-anchor" href="#what-aosc-tries-to-preserve" aria-label="Permalink to &quot;What AOSC Tries to Preserve&quot;">​</a></h2><p>For supported routing and transform configurations, AOSC aims for the target index to reflect the source index at cutover time after applying the configured transform.</p><p>This is not a blanket guarantee for every index configuration. Custom routing, unsupported transform behavior, application writes that do not retry, and manual interference can break the expected result.</p><h2 id="backfill" tabindex="-1">Backfill <a class="header-anchor" href="#backfill" aria-label="Permalink to &quot;Backfill&quot;">​</a></h2><p>Each shard worker reads source documents from its source primary and writes transformed documents to the target. Backfill writes use document IDs and routing values from the source document and use idempotent index operations.</p><h2 id="operation-history-replay" tabindex="-1">Operation-History Replay <a class="header-anchor" href="#operation-history-replay" aria-label="Permalink to &quot;Operation-History Replay&quot;">​</a></h2><p>AOSC uses source-shard operation history to replay writes that happen during backfill. Workers track sequence-number progress and replay index/create/delete operations into the target.</p><p>Retention leases are used to keep required operation history available while workers are active.</p><h2 id="routing" tabindex="-1">Routing <a class="header-anchor" href="#routing" aria-label="Permalink to &quot;Routing&quot;">​</a></h2><p>Backfill and replayed index operations preserve <code>_routing</code> when it is present. Delete operations require topology-specific handling because OpenSearch operation history records the deleted <code>_id</code> but not the routing key.</p><p>AOSC supports three routing modes:</p><div class="aosc-table-scroll"><table class="aosc-table"><thead><tr><th>Mode</th><th>Topology</th><th>Correctness boundary</th></tr></thead><tbody><tr><td><code>SAME_SHARD</code></td><td>Source and target have the same shard count.</td><td>Safe for custom routing because each source shard maps to the corresponding target shard.</td></tr><tr><td><code>SPLIT_SHARD</code></td><td>Target shard count is a power-of-2 multiple of the source shard count.</td><td>Safe for custom routing because deletes fan out to the target shard group that can contain documents from the source shard.</td></tr><tr><td><code>BULK_API</code></td><td>Shrink, non-multiple change, or non-power-of-2 expansion.</td><td>Deletes are routed by <code>_id</code>; custom-routed deletes can leave stale target documents.</td></tr></tbody></table></div><p>See <a href="./routing-and-replay">Routing and Replay</a> for the detailed model and the data-loss consent gate.</p><h2 id="convergence" tabindex="-1">Convergence <a class="header-anchor" href="#convergence" aria-label="Permalink to &quot;Convergence&quot;">​</a></h2><p>After the first replay pass, workers continue replaying until the gap to the source global checkpoint is below the configured threshold. At cutover, AOSC write-blocks the source and requires final catch-up to close the gap.</p><h2 id="cutover" tabindex="-1">Cutover <a class="header-anchor" href="#cutover" aria-label="Permalink to &quot;Cutover&quot;">​</a></h2><p>The coordinator:</p><ol><li>Restores target settings needed for readiness.</li><li>Applies a source write block.</li><li>Flushes the source.</li><li>Signals workers to replay final operations.</li><li>Validates source and target document counts, optionally filtered by <code>validation_query</code>.</li><li>Swaps the alias from source to target.</li><li>Removes the source write block when configured.</li></ol><h2 id="important-boundaries" tabindex="-1">Important Boundaries <a class="header-anchor" href="#important-boundaries" aria-label="Permalink to &quot;Important Boundaries&quot;">​</a></h2><ul><li>Backfill and replay write target documents by ID/source/routing; they do not preserve OpenSearch internal <code>_version</code> or <code>_seq_no</code> as target metadata.</li><li>Built-in transforms are update-script based and emit one target document per source document.</li><li>AOSC relies on applications retrying writes rejected during the cutover write block.</li><li>Post-cutover rollback is not automatic and can lose writes if handled incorrectly.</li><li>The target index remains after cancellation or failure for inspection and manual cleanup.</li></ul>',22)])])}const m=t(n,[["render",s]]);export{p as __pageData,m as default};
